using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class SearchTraining : TrainingContentBase
{
    public SearchTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Search Overview",
            Slug = "search-overview",
            Summary = "What global search does, entity types searched, full-text and RAG hybrid search, and keyboard shortcuts.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["search","global-search","navigation"]""",
            ContentJson = """{"body":"## Global Search Overview\n\nGlobal search is always available from the header bar at the top of every page. It provides instant, cross-entity search across six core entity types, combining traditional full-text search with AI-powered RAG (Retrieval-Augmented Generation) results when the AI module is enabled.\n\n### How It Works\n\nThe search input sits in the application header between the breadcrumb navigation and the action buttons. As you type, results appear in a dropdown overlay grouped by entity type. The system searches across six entity types simultaneously:\n\n- **Jobs** — matches on job number and title\n- **Customers** — matches on customer name and company name\n- **Parts** — matches on part number and description\n- **Leads** — matches on company name and contact name\n- **Assets** — matches on asset name and serial number\n- **Expenses** — matches on description and category\n\nSearch requires at least 2 characters before results appear. Results are debounced so the system waits for you to stop typing before querying — this keeps the interface responsive even on large datasets.\n\n### Full-Text Search\n\nThe left column of the search overlay shows traditional full-text results. Each result displays an icon representing the entity type, the primary title (job number, part number, customer name, etc.), a subtitle with additional context, and a type label. Clicking any result navigates you directly to that entity's page or opens its detail dialog.\n\n### AI-Powered RAG Results\n\nWhen the Ollama AI module is running, the search overlay expands to two columns. The right column shows AI results powered by RAG — Retrieval-Augmented Generation. This uses document embeddings stored in PostgreSQL via pgvector to find semantically related content, not just exact text matches.\n\nThe AI column shows:\n- A **generated answer** — a natural-language summary responding to your query\n- **Relevant document chunks** — pieces of indexed content that match your query, each with a relevance score percentage\n\nRAG results are especially useful for questions like 'what jobs involve aluminum machining' or 'which customer ordered the gear housing' — queries where the exact words might not appear in the record but the meaning is captured in indexed documents.\n\n### Keyboard Shortcuts\n\n- **Ctrl+K** — Focus the search input from anywhere in the application. This is the fastest way to start searching without reaching for the mouse.\n- **Escape** — Close the search results overlay and clear the search input\n- **Click a result** — Navigate to that entity and close the overlay\n\n### When to Use Global Search\n\n- When you need to quickly find a job by number or title\n- When looking up a customer or lead by name\n- When you know a part number but don't want to navigate to the Parts page first\n- When you have a vague query and want AI to help find relevant records\n- When jumping between different entity types frequently throughout the day","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Search — Guided Tour",
            Slug = "search-walkthrough",
            Summary = "A guided tour of the global search overlay: search input, result columns, keyboard shortcuts, and AI-powered results.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["search","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Tour Search","steps":[{"element":".app-header__search","popover":{"title":"Global Search Bar","description":"This is the global search input, always available in the header. Type at least 2 characters to start searching across Jobs, Customers, Parts, Leads, Assets, and Expenses simultaneously. Results appear in a dropdown overlay below.","side":"bottom"}},{"element":".app-header__search input","popover":{"title":"Search Input","description":"Type your query here. Search is debounced — results appear after you stop typing. The system searches across job numbers, customer names, part numbers, lead contacts, asset names/serial numbers, and expense descriptions. Press Ctrl+K from anywhere to jump directly to this input.","side":"bottom"}},{"element":".app-header__search kbd","popover":{"title":"Keyboard Shortcut Hint","description":"The Ctrl+K badge reminds you of the keyboard shortcut. Press Ctrl+K from any page to immediately focus the search input without using the mouse. Press Escape to close results and clear the input.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Search Field Reference",
            Slug = "search-field-reference",
            Summary = "Complete reference for search input, entity type groups, result fields, keyboard shortcuts, and RAG integration.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["search","reference"]""",
            ContentJson = """{"title":"Search Field Reference","groups":[{"heading":"Search Input","items":[{"label":"Location","value":"Header bar, between breadcrumb navigation and action buttons. Visible on all pages except onboarding."},{"label":"Minimum characters","value":"2 characters required before search executes. Queries shorter than 2 characters return no results."},{"label":"Debounce","value":"Input is debounced — the system waits for you to stop typing before sending the query. This prevents excessive API calls during fast typing."},{"label":"Result limit","value":"Default 20 results, maximum 50. Results are distributed evenly across entity types (at least 3 per type)."},{"label":"Clear behavior","value":"Navigating to a result or pressing Escape clears the search input and closes the results overlay."}]},{"heading":"Entity Types Searched","items":[{"label":"Job","value":"Searched fields: job_number, title. Icon: work. Results link to /kanban with the job selected."},{"label":"Customer","value":"Searched fields: name, company_name. Icon: people. Results link to /customers."},{"label":"Part","value":"Searched fields: part_number, description. Icon: inventory_2. Results link to /parts."},{"label":"Lead","value":"Searched fields: company_name, contact_name. Icon: trending_up. Results link to /leads."},{"label":"Asset","value":"Searched fields: name, serial_number. Icon: precision_manufacturing. Results link to /assets."},{"label":"Expense","value":"Searched fields: description, category. Icon: receipt_long. Results link to /expenses."}]},{"heading":"Result Fields","items":[{"label":"Icon","value":"Material icon representing the entity type (work, people, inventory_2, trending_up, precision_manufacturing, receipt_long)."},{"label":"Title","value":"Primary identifier: job number, customer name, part number, company name, asset name, or expense description."},{"label":"Subtitle","value":"Secondary context: job title, company name, part description, contact name, serial number, or expense category. May be null."},{"label":"Entity Type label","value":"Text badge showing the type (Job, Customer, Part, Lead, Asset, Expense) for quick identification."},{"label":"URL","value":"Navigation target when clicked. Each entity type routes to its primary page (/kanban, /customers, /parts, /leads, /assets, /expenses)."}]},{"heading":"Keyboard Shortcuts","items":[{"label":"Ctrl+K","value":"Focus the search input from anywhere in the application. Works on all pages. This is the primary way to access search without the mouse."},{"label":"Escape","value":"Close the search results overlay and clear the input. Also unfocuses the search input."},{"label":"Click result","value":"Navigate to the selected entity's page and close the overlay. The search input is cleared automatically."}]},{"heading":"RAG / AI Results (when AI module is active)","items":[{"label":"Two-column layout","value":"When AI is available, the search overlay expands to show two columns: full-text results on the left, AI results on the right."},{"label":"Generated answer","value":"A natural-language summary answering your query, displayed with a lightbulb icon. Generated by the Ollama AI model using RAG context."},{"label":"Document chunks","value":"Relevant text chunks from indexed documents. Each shows the chunk text, the source field it was extracted from, the entity type, and a relevance score as a percentage."},{"label":"Relevance score","value":"Percentage indicating how closely the document chunk matches your query semantically. Higher scores mean stronger relevance."},{"label":"Thinking indicator","value":"A spinning icon with 'Thinking...' text appears while the AI model processes your query. AI results may take slightly longer than full-text results."},{"label":"Fallback","value":"If the AI module is not running or unavailable, the search overlay shows only the single full-text results column. No error is displayed — AI simply degrades gracefully."}]},{"heading":"Search API","items":[{"label":"Endpoint","value":"GET /api/v1/search?q={term}&limit={limit}. Requires authentication. Returns a flat list of SearchResult objects."},{"label":"Query parameter: q","value":"The search term. Must be at least 2 characters. Searches using ILIKE pattern matching (case-insensitive contains)."},{"label":"Query parameter: limit","value":"Maximum number of results to return. Default: 20, maximum: 50. Clamped server-side."},{"label":"Response shape","value":"Array of SearchResult: { entityType, entityId, title, subtitle, icon, url }. Results from all 6 entity types are combined in a single list."},{"label":"UNION ALL query","value":"Server executes a single SQL query with UNION ALL across 6 entity tables. Each entity sub-query has its own LIMIT (total limit / 4, minimum 3 per entity type)."},{"label":"Soft-delete filter","value":"All searches exclude soft-deleted records (deleted_at IS NULL). Job searches also exclude archived jobs (is_archived = false)."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Search Knowledge Check",
            Slug = "search-quiz",
            Summary = "Test your knowledge of global search: keyboard shortcuts, entity types, result layout, and RAG integration.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/dashboard"]""",
            Tags = """["search","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"sr1","text":"You need to quickly find a job but you're currently on the Expenses page. What is the fastest way to start searching?","options":[{"id":"a","text":"Navigate to the Kanban board first, then use the board's search filter"},{"id":"b","text":"Press Ctrl+K to focus the global search input in the header, then type the job number","isCorrect":true},{"id":"c","text":"Go to Reports and run a Job Lookup report"},{"id":"d","text":"Open the sidebar and click the Search menu item"}],"explanation":"Ctrl+K focuses the global search input from any page. You don't need to navigate anywhere first — just press Ctrl+K and start typing. The search bar is always available in the header."},{"id":"sr2","text":"How many entity types does global search query simultaneously?","options":[{"id":"a","text":"3 — Jobs, Parts, and Customers"},{"id":"b","text":"4 — Jobs, Customers, Parts, and Leads"},{"id":"c","text":"6 — Jobs, Customers, Parts, Leads, Assets, and Expenses","isCorrect":true},{"id":"d","text":"All entity types in the database"}],"explanation":"Global search queries 6 entity types in a single UNION ALL query: Jobs, Customers, Parts, Leads, Assets, and Expenses. Each type has its own searchable fields and icon."},{"id":"sr3","text":"You type a single letter 'A' into the search bar. What happens?","options":[{"id":"a","text":"Results appear showing all entities starting with A"},{"id":"b","text":"Nothing — search requires at least 2 characters before executing","isCorrect":true},{"id":"c","text":"An error message appears asking you to type more"},{"id":"d","text":"The AI module generates suggestions based on the letter"}],"explanation":"Global search requires a minimum of 2 characters before it queries the server. Queries shorter than 2 characters return no results. This prevents overly broad searches that would return too many results."},{"id":"sr4","text":"What information does each search result display?","options":[{"id":"a","text":"Only the entity name and a link"},{"id":"b","text":"An icon for the entity type, primary title, subtitle with context, and a type label","isCorrect":true},{"id":"c","text":"A thumbnail image, full description, and creation date"},{"id":"d","text":"The entity ID, database table name, and last modified timestamp"}],"explanation":"Each search result shows four elements: an icon identifying the entity type (work, people, inventory_2, etc.), the primary title (job number, customer name, etc.), a subtitle with additional context, and a type label (Job, Customer, Part, etc.)."},{"id":"sr5","text":"The search overlay shows two columns instead of one. What does this mean?","options":[{"id":"a","text":"There are too many results to fit in one column"},{"id":"b","text":"The AI module is active, showing full-text results on the left and RAG-powered AI results on the right","isCorrect":true},{"id":"c","text":"You are searching across two different databases"},{"id":"d","text":"The screen is wide enough for a two-column layout"}],"explanation":"When the Ollama AI module is running, the search overlay expands to two columns. The left column shows traditional full-text search results, while the right column shows AI-powered RAG results including a generated answer and semantically relevant document chunks."},{"id":"sr6","text":"A RAG search result shows a relevance score of 87%. What does this score represent?","options":[{"id":"a","text":"The percentage of keywords from your query found in the document"},{"id":"b","text":"How semantically similar the document chunk is to your search query, based on vector embeddings","isCorrect":true},{"id":"c","text":"The confidence that the document is not a duplicate"},{"id":"d","text":"The percentage of the document that has been indexed"}],"explanation":"The relevance score is a semantic similarity percentage based on vector embeddings (pgvector). It measures how closely the meaning of the document chunk matches your query, not just keyword overlap. Higher scores indicate stronger semantic relevance."},{"id":"sr7","text":"You search for 'aluminum housing' but no exact matches exist in job titles or part numbers. How can global search still help?","options":[{"id":"a","text":"It cannot — global search only matches exact text in specific fields"},{"id":"b","text":"The AI/RAG column can find semantically related records even without exact keyword matches, returning relevant document chunks and a generated answer","isCorrect":true},{"id":"c","text":"It automatically switches to a fuzzy search mode"},{"id":"d","text":"It searches the full text of all uploaded PDF documents"}],"explanation":"RAG (Retrieval-Augmented Generation) uses vector embeddings to find semantically related content. Even if 'aluminum housing' doesn't appear verbatim in any record, the AI column can find documents that discuss aluminum machining or housing components and present relevant chunks with a generated answer."},{"id":"sr8","text":"You click a Part result in the search overlay. What happens next?","options":[{"id":"a","text":"A detail dialog opens over the current page"},{"id":"b","text":"The application navigates to /parts, the search input is cleared, and the overlay closes","isCorrect":true},{"id":"c","text":"The part information is copied to your clipboard"},{"id":"d","text":"A new browser tab opens with the part details"}],"explanation":"Clicking a search result navigates you to that entity's primary page (in this case /parts). The search input is automatically cleared and the results overlay closes, leaving you on the target page ready to work with the selected record."}]}"""
        });

        Log.Information("Seeded Search training modules");
    }
}
